import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useOrder } from "../context/OrderContext";

// Cấu hình phần thưởng
const REWARDS = [
  { 
    id: "V200K", 
    name: "Voucher 200K", 
    type: "fixed", 
    discount: 200000, 
    maxQuantity: 1, 
    probability: 2, 
    color: "#e53e3e" 
  },
  { 
    id: "V30PERCENT", 
    name: "Giảm 30%", 
    type: "percent", 
    discount: 30, 
    maxQuantity: 5, 
    probability: 10, 
    color: "#d69e2e" 
  },
  { 
    id: "MISS", 
    name: "Chúc may mắn lần sau", 
    type: "none", 
    maxQuantity: Infinity, 
    probability: 88, 
    color: "#718096" 
  }
];

export default function LuckyWheel() {
  const { user } = useAuth();
  const { getOrdersByUser } = useOrder();
  const navigate = useNavigate();
  
  const [spinCount, setSpinCount] = useState(0);
  const [isSpinning, setIsSpinning] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [resultMessage, setResultMessage] = useState("");

  // Giả lập kho lưu trữ số lượng quà trên Frontend
  const [inventory, setInventory] = useState({
    V200K: 1,
    V30PERCENT: 5
  });

  // Tính số lượt quay: Mỗi đơn hàng "delivered" được 1 lượt
  useEffect(() => {
    if (user) {
      // Giả sử có hàm getOrdersByUser, nếu không bạn có thể thay bằng mảng orders lấy từ context
      const orders = getOrdersByUser ? getOrdersByUser(user.id) : [];
      const deliveredOrders = orders.filter(o => o.status === "delivered");
      
      // Ở hệ thống thực tế cần lưu số lượt đã quay vào DB. Ở đây demo tạm gán bằng số đơn thành công.
      setSpinCount(deliveredOrders.length > 0 ? deliveredOrders.length : 1); // Cấp tạm 1 lượt để test nếu chưa có đơn
    }
  }, [user, getOrdersByUser]);

  const spinWheel = () => {
    if (spinCount <= 0 || isSpinning) return;

    setIsSpinning(true);
    setResultMessage("");

    // Thuật toán quay số dựa trên xác suất
    let randomNum = Math.random() * 100;
    let cumulative = 0;
    let selectedReward = REWARDS.find(r => r.id === "MISS"); 

    for (let reward of REWARDS) {
      cumulative += reward.probability;
      if (randomNum <= cumulative) {
        if (reward.id !== "MISS" && inventory[reward.id] > 0) {
          selectedReward = reward;
        }
        break; 
      }
    }

    // Tính toán góc quay
    const sectionAngle = 360 / REWARDS.length;
    const targetIndex = REWARDS.findIndex(r => r.id === selectedReward.id);
    
    // Quay ngẫu nhiên từ 5-8 vòng
    const spinSpins = (Math.floor(Math.random() * 4) + 5) * 360; 
    const stopAngle = spinSpins + (360 - (targetIndex * sectionAngle)) - (sectionAngle / 2);

    setRotation(prev => prev + stopAngle);

    // Đợi hiệu ứng quay kết thúc (4s)
    setTimeout(() => {
      setIsSpinning(false);
      setSpinCount(prev => prev - 1);
      
      if (selectedReward.id !== "MISS") {
        setResultMessage(`🎉 Xin chúc mừng! Bạn trúng: ${selectedReward.name}`);
        setInventory(prev => ({ ...prev, [selectedReward.id]: prev[selectedReward.id] - 1 }));
      } else {
        setResultMessage("😔 " + selectedReward.name);
      }
    }, 4000);
  };

  if (!user) {
    return (
      <div style={styles.accessDenied}>
        <p style={{ fontSize: "64px", margin: 0 }}>🎁</p>
        <h2>Vui lòng đăng nhập để tham gia vòng quay</h2>
        <button style={styles.loginBtn} onClick={() => navigate("/login")}>Đăng nhập ngay</button>
      </div>
    );
  }

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <button style={styles.backBtn} onClick={() => navigate("/")}>← Về trang chủ</button>
        
        <div style={styles.headerBox}>
          <h1 style={styles.title}>🎁 Vòng Quay May Mắn</h1>
          <p style={styles.subtitle}>
            Bạn đang có <span style={styles.highlight}>{spinCount}</span> lượt quay
          </p>
          <p style={{ fontSize: "13px", color: "#718096" }}>
            *Mỗi đơn hàng giao thành công sẽ nhận được 1 lượt quay.
          </p>
        </div>

        <div style={styles.wheelWrapper}>
          <div style={styles.pointer}>▼</div>
          <div style={{ ...styles.wheel, transform: `rotate(${rotation}deg)` }}>
            {REWARDS.map((reward, index) => {
              const angle = (360 / REWARDS.length) * index;
              return (
                <div 
                  key={reward.id} 
                  style={{
                    ...styles.wheelSection,
                    backgroundColor: reward.color,
                    transform: `rotate(${angle}deg) skewY(${-(90 - 360/REWARDS.length)}deg)`
                  }}
                >
                  <span style={styles.wheelText}>{reward.name}</span>
                </div>
              );
            })}
          </div>
        </div>

        <button 
          style={{ ...styles.spinBtn, opacity: (spinCount <= 0 || isSpinning) ? 0.5 : 1 }} 
          onClick={spinWheel}
          disabled={spinCount <= 0 || isSpinning}
        >
          {isSpinning ? "ĐANG QUAY..." : "QUAY NGAY"}
        </button>

        {resultMessage && (
          <div style={styles.resultBox}>
            {resultMessage}
          </div>
        )}

        <div style={styles.inventoryInfo}>
          <h3 style={{ margin: "0 0 10px", color: "#2d3748", fontSize: "15px" }}>Kho quà tặng tuần này:</h3>
          <ul style={{ margin: 0, paddingLeft: "20px", color: "#4a5568", fontSize: "14px" }}>
            <li><strong>Voucher 200K (Đơn 0đ):</strong> Còn {inventory.V200K}/1 suất</li>
            <li><strong>Giảm 30% (Tối đa 200K):</strong> Còn {inventory.V30PERCENT}/5 suất</li>
          </ul>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: { backgroundColor: "#f7fafc", minHeight: "100vh", fontFamily: "sans-serif" },
  container: { maxWidth: "600px", margin: "0 auto", padding: "40px 16px", display: "flex", flexDirection: "column", alignItems: "center" },
  accessDenied: { textAlign: "center", padding: "80px", backgroundColor: "#f7fafc", minHeight: "100vh" },
  loginBtn: { backgroundColor: "#38a169", color: "white", border: "none", padding: "12px 24px", borderRadius: "8px", cursor: "pointer", fontSize: "15px", fontWeight: "600", marginTop: "16px" },
  backBtn: { alignSelf: "flex-start", background: "none", border: "none", color: "#38a169", fontSize: "14px", fontWeight: "600", cursor: "pointer", padding: "0 0 20px" },
  
  headerBox: { textAlign: "center", marginBottom: "30px" },
  title: { color: "#276749", fontSize: "32px", fontWeight: "900", margin: "0 0 8px" },
  subtitle: { color: "#4a5568", fontSize: "16px", margin: "0 0 4px" },
  highlight: { color: "#e53e3e", fontWeight: "800", fontSize: "20px" },
  
  wheelWrapper: { position: "relative", width: "320px", height: "320px", marginBottom: "40px", borderRadius: "50%", boxShadow: "0 10px 30px rgba(0,0,0,0.15)" },
